from math import log2
BASE=255

data=Path('data.txt').read_bytes()
print(len(data), len(set(data)), sorted(set(b for b in data if b>=128))[:20])

# bit sequence helpers
def enc_int_bits(x,tmp0,base_ctx):
    y=x+(1<<tmp0)
    m=y.bit_length()-1
    assert m>=tmp0
    bits=[]
    ctxbase=base_ctx*99
    for t in range(tmp0+1,m+1): bits.append((ctxbase+t,0))
    bits.append((ctxbase+m+1,1))
    for k in range(m-1,-1,-1): bits.append((ctxbase,(y>>k)&1))
    return bits

def lit_bits(byte):
    if byte < 128:
        sign=0; mag=byte
    else:
        sign=1; mag=256-byte
    return [(1,0),(8,sign)] + enc_int_bits(mag,4,9)

def copy_bits(dist,l):
    # z=Q-val-1 dist=val+1; tmp=lenval+1
    return [(1,1)] + enc_int_bits(dist-1,5,2) + enc_int_bits(l-1,2,3)

def encode_size(tokens):
    # tokens list ('L', b) or ('C', dist,len)
    bits=[]
    bits += enc_int_bits(len(tokens),9,0)
    for t in tokens:
        if t[0]=='L': bits += lit_bits(t[1])
        else: bits += copy_bits(t[1],t[2])
    counts={} # ctx->[c0,c1]
    R=1; O=0; n=0
    for ctx,b in bits:
        if R<BASE:
            R*=BASE; O*=BASE; n+=1
        c0,c1=counts.get(ctx,(0,0))
        split=R*(c0+1)//(c0+c1+2)
        if b:
            O+=split; R-=split; c1+=1
        else:
            R=split; c0+=1
        counts[ctx]=(c0,c1)
        if R<=0:
            print('zero range', ctx,b,c0,c1)
            raise SystemExit
    return n,len(bits)

# Greedy longest match with min len threshold by naive search in window all previous
N=len(data)
for minlen in range(2,9):
  toks=[]; i=0
  while i<N:
    best=(0,0)
    # search all dist previous, allow overlap
    maxdist=i
    for dist in range(1,maxdist+1):
        l=0
        # cap perhaps remaining
        while i+l<N and data[i+l]==data[i-dist+l]:
            l+=1
        if l>best[1]: best=(dist,l)
    dist,l=best
    if l>=minlen:
        toks.append(('C',dist,l)); i+=l
    else:
        toks.append(('L',data[i])); i+=1
  print('minlen',minlen,'tokens',len(toks),'size',encode_size(toks))
