    return [(1,1)] + enc_int_bits(dist-1,5,2) + enc_int_bits(l-1,2,3)

def token_bits(tok):
    if tok[0]=='L':
        return lit_bits(tok[1])
    return copy_bits(tok[1],tok[2])

def bits_to_bytes(bits):
    counts={}
    R=1
    O=0
    n=0
    for ctx,b in bits:
        if R<BASE:
            R*=BASE
            O*=BASE
            n+=1
        c0,c1=counts.get(ctx,(0,0))
        split=R*(c0+1)//(c0+c1+2)
        if not (0 < split < R):
            raise RuntimeError((ctx,b,R,c0,c1,split))
